for (const item of $input.all()) {
  const body = item.json.email_body || '';
  const newBody = body
    .replace(/\b\d{3}-\d{2}-\d{4}\b/g, '[REDACTED]')
    .replace(/\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b/g, '[REDACTED]')
    .replace(/\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g, '[REDACTED]');

  item.json.hasPII = newBody !== body;
  item.json.sanitized_body = newBody;
}

return $input.all();

const crypto = require('crypto');
const input = $('Execute Workflow Trigger').first().json;
const draft = $('Create Draft').first().json || {};
const generated = $('Generate Reply').first().json || {};

const token = crypto.randomBytes(32).toString('hex');
const draftId = draft.id || draft.draftId || draft.draft_id || draft.message?.id || draft.messageId || null;
const subject = `Re: ${(input.email_subject || '').replace(/^Re:\s*/i, '')}`;
const draftText = generated.response || generated.text || '';
const now = new Date();
const expiresAt = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000).toISOString();

if (!draftId) {
  throw new Error('Gmail draft was created but no draft id was returned');
}

return [{
  json: {
    request_type: 'email_draft_send',
    source_workflow: 'EMAIL__GenerateDraft',
    status: 'pending',
    expires_at: expiresAt,
    draft_id: draftId,
    event_id: input.event_id || null,
    recipient: input.sender,
    subject,
    thread_id: input.threadId || null,
    message_id: input.messageId || null,
    classification: input.classification || {},
    approval_token: token,
    draft_preview: draftText.substring(0, 600),
    request_payload: {
      approval_token: token,
      draft_id: draftId,
      event_id: input.event_id || null,
      to: input.sender,
      subject,
      thread_id: input.threadId || null,
      message_id: input.messageId || null,
      classification: input.classification || {},
      draft_preview: draftText.substring(0, 600),
      created_at: now.toISOString()
    }
  }
}];

const approval = $('Create Approval Request').first().json || {};
const prepared = $('Prepare Approval Request').first().json;

const baseUrl = 'https://edwin-bayog.app.n8n.cloud/webhook/api/email/approve-send';
const approvalId = approval.id;
const token = prepared.approval_token;

if (!approvalId) {
  throw new Error('Approval row was created but no approval id was returned');
}

const approveUrl = `${baseUrl}?decision=approve&approval_id=${encodeURIComponent(approvalId)}&token=${encodeURIComponent(token)}`;
const rejectUrl = `${baseUrl}?decision=reject&approval_id=${encodeURIComponent(approvalId)}&token=${encodeURIComponent(token)}`;

return [{
  json: {
    channel: '#email-routing',
    approval_id: approvalId,
    draft_id: prepared.draft_id,
    approve_url: approveUrl,
    reject_url: rejectUrl,
    message: `*AI Draft Ready for Approval*\n*To:* ${prepared.recipient}\n*Subject:* ${prepared.subject}\n*Category:* ${prepared.classification?.category || '(none)'}\n*Urgency:* ${prepared.classification?.urgency || '(none)'}\n*Approval expires:* ${prepared.expires_at}\n\n*Draft Preview:*\n>>> ${prepared.draft_preview.substring(0, 500)}${prepared.draft_preview.length > 500 ? '...' : ''}\n\n<${approveUrl}|Approve and send> | <${rejectUrl}|Reject draft>`
  }
}];

const prepared = $('Prepare Approval Request').first().json;
const notification = $('Prepare Reviewer Notification').first().json;

return [{
  json: {
    workflow_name: 'EMAIL__GenerateDraft',
    execution_id: $execution.id,
    log_type: 'action',
    action: 'draft_created_pending_approval',
    input_payload: {
      event_id: prepared.event_id,
      recipient: prepared.recipient,
      subject: prepared.subject,
      classification: prepared.classification
    },
    output_payload: {
      approval_id: notification.approval_id,
      draft_id: prepared.draft_id,
      expires_at: prepared.expires_at
    },
    status: 'success'
  }
}];

const prepared = $('Prepare Approval Request').first().json;
const notification = $('Prepare Reviewer Notification').first().json;

return [{
  json: {
    success: true,
    draft_id: prepared.draft_id,
    approval_id: notification.approval_id,
    approval_status: 'pending',
    expires_at: prepared.expires_at,
    approve_url: notification.approve_url,
    reject_url: notification.reject_url
  }
}];
